import React, { useState, useEffect } from 'react';
import axios from 'axios';

function AdminDashboard() {
  const [requests, setRequests] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => { fetchRequests(); }, []);

  const fetchRequests = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/requests');
      setRequests(res.data);
      setLoading(false);
    } catch (err) { console.error(err); setLoading(false); }
  };

  const handleUpdate = async (id, updatedData) => {
    try {
      await axios.put(`http://localhost:5000/api/update-status/${id}`, updatedData);
      fetchRequests(); 
    } catch (err) { alert("Error updating!"); }
  };

  if (loading) return <div className="text-center py-5">Loading Admin Panel...</div>;

  return (
    <div className="container py-5">
      <h2 className="fw-bold mb-4">Admin <span className="text-primary">Control Panel</span></h2>

      <div className="row g-4">
        {requests.map((project) => {
          const remaining = project.totalBudget - project.advancePaid;

          return (
            <div key={project._id} className="col-12">
              <div className="card shadow-sm border-0 rounded-4 p-4 mb-2">
                <div className="row align-items-center">
                  
                  {/* 1. Client Info */}
                  <div className="col-md-3">
                    <h5 className="fw-bold mb-0 text-capitalize">{project.fullName}</h5>
                    <small className="text-primary fw-bold">{project.serviceType}</small>
                    <p className="small text-muted mb-0">{project.email}</p>
                  </div>

                  {/* 2. Progress Slider */}
                  <div className="col-md-3 px-4">
                    <div className="d-flex justify-content-between mb-1">
                      <small className="fw-bold">Progress: {project.progress}%</small>
                    </div>
                    <input 
                      type="range" className="form-range" min="0" max="100" 
                      value={project.progress} 
                      onChange={(e) => handleUpdate(project._id, { progress: e.target.value })}
                    />
                  </div>

                  {/* 3. Payment Section (Buttons for Editing) */}
                  <div className="col-md-3 text-center border-start border-end">
                    <div className="mb-2">
                      <small className="text-muted d-block">Remaining Balance</small>
                      <h4 className={`fw-bold mb-0 ${remaining > 0 ? 'text-danger' : 'text-success'}`}>
                        ₹{remaining}
                      </h4>
                    </div>
                    
                    {/* EDIT BUTTONS ARE HERE */}
                    <div className="d-flex justify-content-center gap-2">
                      <button 
                        className="btn btn-sm btn-light border fw-bold" 
                        onClick={() => {
                          const budget = prompt("Enter Total Budget:", project.totalBudget);
                          if(budget) handleUpdate(project._id, { totalBudget: budget });
                        }}
                      >
                        Set Budget
                      </button>
                      <button 
                        className="btn btn-sm btn-light border fw-bold"
                        onClick={() => {
                          const paid = prompt("Enter Amount Paid by Client:", project.advancePaid);
                          if(paid) {
                            const status = Number(paid) >= project.totalBudget ? 'Paid' : 'Unpaid';
                            handleUpdate(project._id, { advancePaid: paid, paymentStatus: status });
                          }
                        }}
                      >
                        Update Paid
                      </button>
                    </div>
                  </div>

                  {/* 4. Final Actions */}
                  <div className="col-md-3 text-end">
                    {project.paymentStatus === 'Paid' ? (
                      <span className="badge bg-success p-2 px-3 rounded-pill">✅ Fully Paid</span>
                    ) : (
                      <button 
                        className="btn btn-outline-success btn-sm fw-bold px-3 rounded-pill"
                        onClick={() => handleUpdate(project._id, { advancePaid: project.totalBudget, paymentStatus: 'Paid' })}
                      >
                        Mark Full Paid
                      </button>
                    )}
                    <button className="btn btn-link text-danger ms-2" onClick={() => axios.delete(`http://localhost:5000/api/delete-request/${project._id}`).then(fetchRequests)}>
                      <i className="fas fa-trash"></i>
                    </button>
                  </div>

                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

export default AdminDashboard;
